import{_ as r,c as o,b as e,d as t,a as n,o as i}from"./app.80edbbb0.js";const y=JSON.parse('{"title":"What Is Beeminder?","description":"","frontmatter":{},"headers":[{"level":2,"title":"How it works","slug":"how-it-works"},{"level":2,"title":"Key concepts","slug":"key-concepts"},{"level":2,"title":"Learn more","slug":"learn-more"}],"relativePath":"what-is-beeminder.md"}'),s={name:"what-is-beeminder.md"};function l(h,a,d,m,g,u){return i(),o("div",null,[...a[0]||(a[0]=[e("h1",{id:"what-is-beeminder",tabindex:"-1"},[t("What Is Beeminder? "),e("a",{class:"header-anchor",href:"#what-is-beeminder","aria-hidden":"true"},"#")],-1),e("p",null,[t("Beeminder is a service that helps you keep track of what you "),e("em",null,"want"),t(" to be doing, but maybe are having trouble actually following through. It takes data, either that you enter or that's automatically entered from dozens of different services (see "),e("a",{href:"./integrations.html"},"Integrations"),t("), and it keeps track of data in a cool graph! The catch is that you set an amount you must do per day/week/month, and if that amount isn't met then you get charged money. That's the "),e("em",null,"sting"),t(" of Beeminder!")],-1),e("iframe",{width:"560",height:"315",src:"https://www.youtube-nocookie.com/embed/ILf8yPNSbZY",title:"YouTube video player",frameborder:"0",allow:"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share",allowfullscreen:""},null,-1),n('<h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-hidden="true">#</a></h2><ol><li><strong>Pick a goal and a rate.</strong> Decide what you want to track and how much of it you&#39;ll commit to \u2014 for example, &quot;run 10 miles a week&quot; or &quot;spend no more than 30 minutes a day on social media.&quot;</li><li><strong>Beeminder draws your bright red line.</strong> Your commitment becomes a line on a graph. As long as your datapoints stay on the right side of it, you&#39;re on track.</li><li><strong>Feed it data.</strong> Enter datapoints by hand, or connect one of the many <a href="./integrations.html">integrations</a> to report your progress automatically.</li><li><strong>Stay on the line.</strong> The day you&#39;re at risk of crossing it is an <em>eep day</em> \u2014 you have to do something that day, or you&#39;ll derail.</li><li><strong>Derail and you pay.</strong> Going off your line triggers your pledge, and each derailment bumps the pledge up to keep the sting real.</li></ol><h2 id="key-concepts" tabindex="-1">Key concepts <a class="header-anchor" href="#key-concepts" aria-hidden="true">#</a></h2><p>Beeminder has its own vocabulary. Here are the essentials \u2014 see the official <a href="https://blog.beeminder.com/glossary/" target="_blank" rel="noopener noreferrer">Glossary</a> for the full list.</p><ul><li><strong>Bright red line</strong> \u2014 the line on your graph you commit to staying on the right side of. (You may still see this called the <em>Yellow Brick Road</em> in older posts; it&#39;s the same idea.)</li><li><strong>Datapoint</strong> \u2014 a single number you (or an integration) report toward your goal.</li><li><strong>Eep day</strong> \u2014 a day when you must enter data or do the thing, or you&#39;ll derail.</li><li><strong>Derailing</strong> \u2014 going off your bright red line. This is what triggers your pledge.</li><li><strong>Pledge / the sting</strong> \u2014 the money you put on the line. After a derailment it escalates up a schedule ($0 \u2192 $5 \u2192 $10 \u2192 $30 \u2192 \u2026) so the commitment keeps its bite. See <a href="https://www.beeminder.com/money" target="_blank" rel="noopener noreferrer">how the money works</a>.</li><li><strong>Akrasia</strong> \u2014 acting against your own better judgment. Beeminder is a commitment device designed to counter it; see <a href="./philosophy.html">The Beeminder Philosophy</a>.</li><li><strong>Akrasia horizon</strong> \u2014 changes you make to a goal only take effect after about a week, so you can&#39;t dodge the sting at the last minute.</li><li><strong>Autodata</strong> \u2014 data sent to Beeminder automatically by an <a href="./integrations.html">integration</a> instead of entered by hand.</li></ul><h2 id="learn-more" tabindex="-1">Learn more <a class="header-anchor" href="#learn-more" aria-hidden="true">#</a></h2><ul><li><a href="./philosophy.html">The Beeminder Philosophy</a> \u2014 why the sting works</li><li><a href="./getting-started.html">Getting Started</a> \u2014 official guides for new users</li><li><a href="./use-cases.html">Use Cases</a> \u2014 ideas for what to beemind</li><li><a href="./integrations.html">Integrations</a> \u2014 connect the apps you already use</li><li>Official: <a href="https://www.beeminder.com/overview" target="_blank" rel="noopener noreferrer">Overview</a> \xB7 <a href="https://blog.beeminder.com/newbees/" target="_blank" rel="noopener noreferrer">Newbie guide</a> \xB7 <a href="https://www.beeminder.com/faq" target="_blank" rel="noopener noreferrer">FAQ</a> \xB7 <a href="https://blog.beeminder.com/glossary/" target="_blank" rel="noopener noreferrer">Glossary</a></li></ul>',7)])])}var p=r(s,[["render",l]]);export{y as __pageData,p as default};
